Python代码实现# P3865 【模板】ST 表 &amp;&amp; RMQ 问题import mathn, m = map(int, input().split())h = list(map(int, input().split()))# 使用ST表处理最大值max_log = 20f = [[0] * (max_log + 1) for _ in range(n + 1)]for i in range(1, n + 1):    f[i][0] = h[i - 1]for j in range(1, max_log + 1):    i = 1    while i + 2 ** j - 1 &lt;= n:        mid = i + 2 ** (j - 1)        f[i][j] = max(f[i][j - 1], f[mid][j - 1])        i += 1def find(l, r):    k = int(math.log2(r - l + 1))    ma = max(f[l][k], f[r - 2 ** k + 1][k])    return mafor i in range(m):    l, r = map(int, input().split())    print(find(l, r))
