Python代码实现# P1908 逆序对import syssys.setrecursionlimit(1000000)def merge(l, r):    global res, a, b    if l &gt;= r:        return    mid = (l + r) // 2    merge(l, mid)    merge(mid + 1, r)    i = l; j = mid + 1; k = l    while i &lt;= mid and j &lt;= r:        if a[i] &lt;= a[j]:            b[k] = a[i]            k += 1; i += 1        else:            b[k] = a[j]            k += 1; j += 1            res += mid - i + 1    while i &lt;= mid:        b[k] = a[i]        k += 1; i += 1    while j &lt;= r:        b[k] = a[j]        k += 1; j += 1    for i in range(l, r + 1):        a[i] = b[i]n = int(input())a = list(map(int, input().split()))b = [0] * nres = 0merge(0, n - 1)print(res)
